  "asbab_nuzul": {
    "76": [
      {
        "ar": "عن ابن عباس رضي الله عنهما في قوله: { ضَرَبَ ٱللَّهُ مَثَلًا عَبْدًا مَّمْلُوكًا لَّا يَقْدِرُ عَلَىٰ شَىْءٍ } قال: نزلت في رجل من قريش وعبده، يعني قوله: { عَبْدًا مَّمْلُوكًا } الآية، وفي قوله: { وَضَرَبَ ٱللَّهُ مَثَلًا رَّجُلَيْنِ أَحَدُهُمَآ أَبْكَمُ } إِلى قوله: { وَهُوَ عَلَىٰ صِرَٰطٍ مُّسْتَقِيمٍ } قال: هو عثمان بن عفان، قال: والأبكم أينما يوجهه لا يأت بخير، قال: هو مولى عثمان بن عفان، كان عثمان ينفق عليه، ويكلفه، ويكفيه المؤونة، وكان الآخر يكره الإسلام، ويأباه، وينهاه عن الصدقة والمعروف فنزلت فيهما. واللفظ لابن جرير في التفسير.",
        "id": ""
      }
    ],
    "103": [
      {
        "ar": "عن عبد الله بن مسلم الحضرمي رضي الله عنه: أنه كان لهم عبدان من أهل غير اليمن، وكانا طفلين، وكان يقال لأحدهما: يسار، والآخر: جبر، فكانا يقرآن التوراة، وكان رسول الله ﷺ ربما جلس إليهما، فقال كفار قريش: إنما يجلس إليهما يتعلم منهما، فأنزل الله تعالى: { لِّسَانُ ٱلَّذِى يُلْحِدُونَ إِلَيْهِ أَعْجَمِىٌّ وَهَـٰذَا لِسَانٌ عَرَبِىٌّ مُّبِينٌ }.\n\nوجاء من حديث ابن عباس رضي الله عنهما شبيهاً به.",
        "id": ""
      }
    ]
  },
